function preHandlerCallback (err, request, reply) {
  if (reply.sent) return

  const context = request[kRouteContext]

  if (!channels.hasSubscribers || context[kFourOhFourContext] === null) {
    preHandlerCallbackInner(err, request, reply)
  } else {
    const store = {
      request,
      reply,
      async: false,
      route: {
        url: context.config.url,
        method: context.config.method
      }
    }
    reply[kDiagnosticsStore] = store
    channels.start.runStores(store, preHandlerCallbackInner, undefined, err, request, reply, store)
  }
}

async function onStatus (req, reply) {
  const okResponse = { status: 'ok' }
  if (healthCheck) {
    try {
      const checkResult = await healthCheck(fastify)
      if (!checkResult) {
        req.log.error('external health check failed')
        reply.status(SERVICE_UNAVAILABLE).header('Retry-After', retryAfter)
        throw underPressureError
      }

      return Object.assign(okResponse, checkResult)
    } catch (err) {
      req.log.error({ err }, 'external health check failed with error')
      reply.status(SERVICE_UNAVAILABLE).header('Retry-After', retryAfter)
      throw underPressureError
    }
  }

  return okResponse
}

function cli (args) {
  const opts = parseArgs(args, {
    options: {
      integrate: { type: 'boolean' }
    }
  })
  const dir = opts._[0]

  if (dir && existsSync(dir)) {
    if (dir !== '.' && dir !== './') {
      log('error', 'directory ' + opts._[0] + ' already exists')
      process.exit(1)
    }
  }
  if (dir === undefined) {
    log('error', 'must specify a directory to \'fastify generate\'')
    process.exit(1)
  }
  if (!opts.integrate && existsSync(path.join(dir, 'package.json'))) {
    log('error', 'a package.json file already exists in target directory. retry with the --integrate flag to proceed')
    process.exit(1)
  }

  generate(dir, pluginTemplate).catch(function (err) {
    if (err) {
      log('error', err.message)
      process.exit(1)
    }
  })
}

function decorateConstructor (konstructor, name, fn, dependencies) {
  const instance = konstructor.prototype
  if (Object.hasOwn(instance, name) || hasKey(konstructor, name)) {
    throw new FST_ERR_DEC_ALREADY_PRESENT(name)
  }

  konstructor[kHasBeenDecorated] = true
  checkDependencies(konstructor, name, dependencies)

  if (fn && (typeof fn.getter === 'function' || typeof fn.setter === 'function')) {
    Object.defineProperty(instance, name, {
      get: fn.getter,
      set: fn.setter
    })
  } else if (typeof fn === 'function') {
    instance[name] = fn
  } else {
    konstructor.props.push({ key: name, value: fn })
  }
}

function buildRegularRequest (R) {
  const props = R.props.slice()
  function _Request (id, params, req, query, log, context) {
    this.id = id
    this[kRouteContext] = context
    this.params = params
    this.raw = req
    this.query = query
    this.log = log
    this.body = undefined

    let prop
    for (let i = 0; i < props.length; i++) {
      prop = props[i]
      this[prop.key] = prop.value
    }
  }
  Object.setPrototypeOf(_Request.prototype, R.prototype)
  Object.setPrototypeOf(_Request, R)
  _Request.props = props
  _Request.parent = R

  return _Request
}

function buildRouterOptions (options, defaultOptions) {
  const routerOptions = options.routerOptions == null
    ? Object.create(null)
    : Object.assign(Object.create(null), options.routerOptions)

  const usedDeprecatedOptions = routerKeys.filter(key => Object.hasOwn(options, key))

  if (usedDeprecatedOptions.length > 0) {
    FSTDEP022(usedDeprecatedOptions.join(', '))
  }

  for (const key of routerKeys) {
    if (!Object.hasOwn(routerOptions, key)) {
      routerOptions[key] = options[key] ?? defaultOptions[key]
    }
  }

  return routerOptions
}

// Gets template as string (or precompiled for Handlebars)
  // from LRU cache or filesystem.
  const getTemplate = async function (file) {
    if (typeof file === 'function') {
      return file
    }
    let isRaw = false
    if (typeof file === 'object' && file.raw) {
      isRaw = true
      file = file.raw
    }
    const data = fastify[viewCache].get(getCacheKey(file))
    if (data && prod) {
      return data
    }
    if (isRaw) {
      return onTemplatesLoaded(file, file)
    }
    const fileData = await readFileSemaphore(join(templatesDir, file))
    return onTemplatesLoaded(file, fileData)
  }

const getPartials = async function (page, { partials, requestedPath }) {
  const cacheKey = getPartialsCacheKey(page, partials, requestedPath)
  const partialsObj = fastify[viewCache].get(cacheKey)
  if (partialsObj && prod) {
    return partialsObj
  } else {
    const partialKeys = Object.keys(partials)
    if (partialKeys.length === 0) {
      return {}
    }
    const partialsHtml = {}
    await Promise.all(partialKeys.map(async (key) => {
      partialsHtml[key] = await readFileSemaphore(join(templatesDir, partials[key]))
    }))
    fastify[viewCache].set(cacheKey, partialsHtml)
    return partialsHtml
  }
}

async function view (page, data, opts) {
  data = Object.assign({}, defaultCtx, this.locals, data)
  if (typeof page === 'function') {
    return page(data)
  }
  let isRaw = false
  if (typeof page === 'object' && page.raw) {
    isRaw = true
    page = page.raw.toString()
  } else {
    // append view extension
    page = getPage(page, type)
  }
  const toHtml = fastify[viewCache].get(getCacheKey(page))

  if (toHtml && prod) {
    return toHtml(data)
  } else if (isRaw) {
    const compiledPage = readCallbackParser(page, page, opts)
    return compiledPage(data)
  }

  const file = await readFileSemaphore(join(templatesDir, page))
  const render = readCallback(page, data, opts, file)
  return render(data)
}

