async createHtmlFunction(
  source: string,
  scope: FastifyInstance,
  config: RuntimeConfig,
): Promise<ReplyDotHtmlFunction> {
  const indexHtmlTemplate = await config.createHtmlTemplateFunction(source)
  if (config.spa) {
    return function () {
      this.type('text/html')
      this.send(indexHtmlTemplate({ element: '' }))
      return this
    }
  }
  if (config.hasRenderFunction) {
    return async function (ctx?: ReplyDotRenderResult) {
      this.type('text/html')
      this.send(await indexHtmlTemplate(ctx ?? (await this.render(ctx))))
      return this
    }
  }
  return async function (ctx?: ReplyDotRenderResult) {
    this.type('text/html')
    this.send(await indexHtmlTemplate(ctx!))
    return this
  }
}

createRouteHandler(
  { client, route }: ClientRouteArgs,
  scope: FastifyInstance,
  config: RuntimeConfig,
): RouteHandlerMethod {
  if (config.hasRenderFunction) {
    return async (req, reply) => {
      const page = await reply.render({
        app: scope,
        req,
        reply,
        client,
        route,
      })
      return reply.html(page)
    }
  }
  return async (req, reply) => {
    const page = await route?.default?.({ app: scope, req, reply })
    return reply.html({
      app: scope,
      req,
      reply,
      client,
      route,
      element: page,
    })
  }
}

function * filesFromFields (container) {
  try {
    const fields = Array.isArray(container) ? container : Object.values(container)
    for (let i = 0; i < fields.length; ++i) {
      const field = fields[i]
      if (Array.isArray(field)) {
        for (const subField of filesFromFields.call(this, field)) {
          yield subField
        }
      }
      if (!field.file) {
        continue
      }
      if (!field._buf) {
        throw new FileBufferNotFoundError()
      }
      field.file = Readable.from(field._buf)
      yield field
    }
  } catch (err) {
    this.log.error({ err }, 'save request file failed')
    throw err
  }
}

function preProcessDot (templatesDir, options) {
  // Process all templates to in memory functions
  // https://github.com/olado/doT#security-considerations
  const destinationDir = options.destination || join(__dirname, 'out')
  if (!existsSync(destinationDir)) {
    mkdirSync(destinationDir)
  }

  const renderer = engine.process(Object.assign(
    {},
    options,
    {
      path: templatesDir,
      destination: destinationDir
    }
  ))

  // .jst files are compiled to .js files so we need to require them
  for (const file of readdirSync(destinationDir, { withFileTypes: false })) {
    renderer[basename(file, '.js')] = require(resolve(join(destinationDir, file)))
  }
  if (Object.keys(renderer).length === 0) {
    this.log.warn(`WARN: no template found in ${templatesDir}`)
  }

  return renderer
}

function resolveBodyParams (opts, body, schema, consumes, ref) {
  const resolved = convertJsonSchemaToOpenapi3(opts, ref.resolve(schema))

  if (resolved.content?.[Object.keys(resolved.content)[0]].schema) {
    for (const contentType in schema.content) {
      body.content[contentType] = schemaToMediaRecursive(resolved.content[contentType].schema)
    }
  } else {
    if ((Array.isArray(consumes) && consumes.length === 0) || consumes === undefined) {
      consumes = ['application/json']
    }

    const media = schemaToMediaRecursive(resolved)
    consumes.forEach((consume) => {
      body.content[consume] = media
    })

    if (resolved?.description) {
      body.description = resolved.description
    }
  }
}

function resolveCommonParams (opts, container, parameters, schema, ref, sharedSchemas, securityIgnores) {
  const schemasPath = '#/components/schemas/'
  let resolved = convertJsonSchemaToOpenapi3(opts, ref.resolve(schema))

  // if the resolved definition is in global schema
  if (resolved.$ref?.startsWith(schemasPath)) {
    const parts = resolved.$ref.split(schemasPath)
    const pathParts = parts[1].split('/')
    resolved = pathParts.reduce((resolved, pathPart) => resolved[pathPart], ref.definitions().definitions)
  }

  const arr = plainJsonObjectToOpenapi3(opts, container, resolved, { ...sharedSchemas, ...ref.definitions().definitions }, securityIgnores)
  arr.forEach(swaggerSchema => parameters.push(swaggerSchema))
}

function readCallbackParser (page, html, localOptions) {
  if ((type === 'ejs') && viewExt && !globalOptions.includer) {
    globalOptions.includer = (originalPath, parsedPath) => ({
      filename: parsedPath || join(templatesDir, originalPath + '.' + viewExt)
    })
  }
  if (localOptions) {
    for (const key in globalOptions) {
      if (!Object.hasOwn(localOptions, key)) localOptions[key] = globalOptions[key]
    }
  } else localOptions = globalOptions

  const compiledPage = engine.compile(html, localOptions)

  fastify[viewCache].set(getCacheKey(page), compiledPage)
  return compiledPage
}

function readCallback (page, _data, localOptions, html) {
  globalOptions.filename = join(templatesDir, page)
  return readCallbackParser(page, html, localOptions)
}

